        1. Search the web for information using the search tool (make 2-3 searches with different queries).
        2. Take notes on key findings using the note-taking tool.
        3. After gathering enough information, retrieve your notes and provide a comprehensive summary.

        Always cite your sources. Be thorough but concise.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and summarizing findings",
    tools: tools);

// --- Run ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

using var cts = new CancellationTokenSource(TimeSpan.FromMinutes(3));
