    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    cancellationToken: cts.Token))
{
    if (update.Text is { Length: > 0 })
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine();

if (notebook.Notes.Count > 0)
